/* ============================================================================
   ΠΕΡΙΓΡΑΦΕΣ ΠΡΟΣΦΟΡΩΝ — συνεργαζόμενο αρχείο του «Αντλίες CRM» (v3)
   ----------------------------------------------------------------------------
   Το έγγραφο παράγεται από ΚΑΛΟΥΠΙ Word (πρότυπο της εταιρείας, ενσωματωμένο
   εδώ ως base64): κρατάει επικεφαλίδα, υποσέλιδο, φωτογραφίες, κουτιά κτιρίου
   και πίνακες ακριβώς όπως τα έφτιαξε ο χρήστης. Το πρόγραμμα αλλάζει ΜΟΝΟ τις
   σημαδούρες @@...@@ μέσα στο word/document.xml και ξαναπακετάρει το .docx.
   Δεν χρειάζεται καμία εξωτερική βιβλιοθήκη.
   Νέο μοντέλο/σειρά: νέα εγγραφή στο MODELS (κείμενα) ή νέο καλούπι.
   ============================================================================ */
window.PERIGRAFES=(function(){
  'use strict';

  // ---------- Το καλούπι Word (base64) ----------
  var TPL_B64='';

  function b64u8(s){var bin=atob(s),u=new Uint8Array(bin.length);for(var i=0;i<bin.length;i++)u[i]=bin.charCodeAt(i);return u;}
  function fmtE(n){return (n||0).toLocaleString('el-GR',{minimumFractionDigits:2,maximumFractionDigits:2})+' €';}
  function litersFrom(name){var m=String(name||'').match(/(\d+(?:\s*[-–]\s*\d+)?)\s*lit/i);return m?m[1].replace(/\s/g,''):null;}
  function escXml(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&apos;');}

  // ---------- Βιβλιοθήκη σειρών ----------
  var MODELS=[
    {
      key:'atlantic',
      seriesLabel:'Atlantic Alfea',
      match:function(ctx){return ctx.equipType!=='gas'&&ctx.brandId==='atlantic'&&!!ctx.pumpName;},
      // Τύπος: M -> monobloc, S/Excellia/HP -> split (διαιρούμενη)
      _mono:function(n){ if(/Extensa\s*S|Excellia\s*S|Excellia\s*HP|HP\s*AI/i.test(n))return false; return true; },
      // Ψυκτικό: R290 αν το όνομα το περιέχει, αλλιώς R32
      _r290:function(n){ return /R290/i.test(n); },
      // Φωτογραφία περιγραφής: 'new' (monobloc-style) για Extensa M, Excellia S, R290· 'old' για Extensa S & Excellia HP
      photoNew:function(n){ if(/Extensa\s*S/i.test(n))return false; if(/Excellia\s*HP|HP\s*AI/i.test(n))return false; if(/Extensa\s*M|Excellia\s*S|R290/i.test(n))return true; return false; },
      title:function(ctx){return 'Πρόταση: Αντλία θερμότητας Atlantic '+ctx.pumpName+(ctx.pumpKw?' ('+ctx.pumpKw+')':'');},
      techA:function(ctx){var typ=this._mono(ctx.pumpName)?'τύπου monoblock (ενιαία εξωτερική μονάδα)':'διαιρούμενου τύπου (split, με εξωτερική και εσωτερική μονάδα)';return 'Η αντλία θερμότητας αέρα – νερού Atlantic '+ctx.pumpName+' της γαλλικής εταιρίας Atlantic είναι αντλία θερμότητας '+typ+', με τεχνολογία inverter και ';},
      techB:function(ctx){var r=this._r290(ctx.pumpName)?'R290 (προπάνιο), φυσικό ψυκτικό μέσο με ελάχιστο δείκτη περιβαλλοντικού αποτυπώματος (GWP)':'R32';var comp=this._mono(ctx.pumpName)?'Πρόκειται για ενιαία (monoblock) εξωτερική μονάδα, χωρίς ψυκτικές σωληνώσεις εντός της κατοικίας, σε συνδυασμό με το κεντρικό σύστημα ελέγχου.':'Το σύστημα αποτελείται από την εξωτερική μονάδα και την εσωτερική υδραυλική μονάδα, μαζί με το κεντρικό σύστημα ελέγχου.';return 'οικολογικό ψυκτικό μέσο '+r+'. Ανήκει σε υψηλή ενεργειακή κλάση «Α++ έως Α+++»'+(ctx.pumpKw?' και αποδίδει ονομαστική θερμική ισχύ περίπου '+ctx.pumpKw:'')+'. Είναι κατάλληλη για αξιόπιστη λειτουργία σε πολύ χαμηλές εξωτερικές θερμοκρασίες και μπορεί να θερμάνει το νερό έως τους 60 °C, ενώ σε λειτουργία θέρμανσης συστημάτων χαμηλών θερμοκρασιών (ενδοδαπέδια ή fan coils) αποδίδει με πολύ υψηλό βαθμό απόδοσης. Οι κινητήρες της μονάδας είναι συνεχούς ρεύματος (ALL DC). '+comp;},
      caption:function(ctx){return 'Η Atlantic '+ctx.pumpName+' εντάσσεται διακριτικά και αρμονικά σε κάθε χώρο.';},
      adv1:function(ctx){return 'Η αντλία θερμότητας Atlantic '+ctx.pumpName+' αποτελεί μια ενεργειακά αποδοτική και «πράσινη» λύση, καθώς αξιοποιεί την ενέργεια του εξωτερικού αέρα για την κάλυψη των θερμικών αναγκών της κατοικίας με πολύ χαμηλή κατανάλωση ηλεκτρικής ενέργειας.';}
    }
  ];

  // ---------- Κείμενα δεδομένων κτιρίου ----------
  var ZONE_TEMP={A:'-3',B:'-8',C:'-13',D:'-20'};
  var INS_LABEL={
    pre1979:'Κατασκευή πριν το 1979 — χωρίς θερμομόνωση',
    y1979:'Κατασκευή 1979–1989 — αρχική εφαρμογή Κανονισμού Θερμομόνωσης',
    y1990:'Κατασκευή 1990–1999 — τυπική εφαρμογή Κανονισμού Θερμομόνωσης',
    y2000:'Κατασκευή 2000–2009 — ενισχυμένη θερμομόνωση',
    kenak:'Κατασκευή 2010+ — κατά ΚΕΝΑΚ',
    nzeb:'Κτήριο σχεδόν μηδενικής κατανάλωσης (nZEB)'
  };
  var FLOOR_LABEL={ground:'Επί εδάφους',pilotis:'Επάνω από πυλωτή',closed:'Επάνω από κλειστό μη θερμαινόμενο χώρο'};
  var CEIL_LABEL={roof:'Ταράτσα / τελευταίος όροφος',attic:'Κάτω από κεραμοσκεπή',closed:'Κάτω από κλειστό μη θερμαινόμενο χώρο'};

  // ---------- Κείμενα υλικών / εργασιών ----------
  function distConn(dist){
    if(!dist)return 'το υφιστάμενο δίκτυο διανομής';
    if(dist.indexOf('ενδοδαπέδια')>=0)return 'τον συλλέκτη της θέρμανσης δαπέδου';
    if(dist.indexOf('σώματα')>=0)return 'το δίκτυο των θερμαντικών σωμάτων';
    if(dist.indexOf('fan')>=0)return 'το δίκτυο των fan coils';
    return 'το υφιστάμενο δίκτυο διανομής';
  }
  function distTarget(dist){
    if(!dist)return 'το δίκτυο διανομής της θέρμανσης';
    if(dist.indexOf('ενδοδαπέδια')>=0)return 'την ενδοδαπέδια θέρμανση';
    if(dist.indexOf('σώματα')>=0)return 'τα θερμαντικά σώματα';
    if(dist.indexOf('fan')>=0)return 'τα fan coils';
    return 'το δίκτυο διανομής της θέρμανσης';
  }
  var MAT_WHITELIST={
    av:'Αντικραδασμική βάση εξωτερικής μονάδας',
    sc:'Συσκευή καθοδικής προστασίας StopCor A3 (ηλεκτρονικό ανόδιο μαγνησίου) για την προστασία της εγκατάστασης από διάβρωση και επικαθίσεις',
    mf:'Φίλτρο Mag-Filter 1" για την προστασία του εναλλάκτη από ρινίσματα και λάσπη του δικτύου',
    ap:'Αυτόματος πληρωτής — σύστημα πλήρωσης της εγκατάστασης'
  };
  function materialsList(pumpSec,bufSec,boilSec,opts){
    var mats=[];
    if(pumpSec){
      ['av','sc','mf','ap'].forEach(function(id){
        if(pumpSec.items.some(function(i){return i.id===id;}))mats.push(MAT_WHITELIST[id]);
      });
    }
    if(bufSec&&bufSec.items.some(function(i){return i.id==='ci1'||/κυκλοφορητ|κυκλ\./i.test(i.name);}))
      mats.push('Κυκλοφορητής για '+distTarget(opts.dist));
    if(boilSec&&boilSec.items.some(function(i){return i.id==='ci2'||/κυκλοφορητ|κυκλ\./i.test(i.name);}))
      mats.push('Κυκλοφορητής φόρτισης του μπόιλερ ζεστού νερού χρήσης');
    if(boilSec&&boilSec.items.some(function(i){return i.id==='v3b'||/3οδη|τρ[ίι]οδη|ηλεκτροβ[άα]να/i.test(i.name);}))
      mats.push('Τρίοδη ηλεκτροβάνα για την εναλλαγή λειτουργίας μεταξύ θέρμανσης και ζεστού νερού χρήσης');
    mats.push('Υλικά σύνδεσης της αντλίας με '+distConn(opts.dist));
    return mats;
  }
  function worksList(pumpSec,bufSec,boilSec,opts){
    var works=[];
    if(opts.rmBoiler||opts.rmTank){
      var rp=[];if(opts.rmBoiler)rp.push('του υφιστάμενου λέβητα');if(opts.rmTank)rp.push('της δεξαμενής πετρελαίου');
      works.push('Αποσύνδεση '+rp.join(' και ')+' από την εγκατάσταση.');
    }
    works.push('Τοποθέτηση της εξωτερικής μονάδας της αντλίας θερμότητας'+(opts.place?' '+opts.place:'')+'.');
    if(bufSec)works.push('Τοποθέτηση και σύνδεση του δοχείου αδρανείας – υδραυλικού διαχωριστή.');
    if(boilSec)works.push('Τοποθέτηση και σύνδεση του μπόιλερ ζεστού νερού χρήσης.');
    if(opts.dist)works.push('Σύνδεση με το υφιστάμενο σύστημα διανομής ('+opts.dist+').');
    if(pumpSec&&pumpSec.items.some(function(i){return i.id==='ap';}))works.push('Τοποθέτηση του συστήματος πλήρωσης της εγκατάστασης.');
    works.push('Τοποθέτηση του χειριστηρίου – αισθητηρίου χώρου.');
    works.push('Θέση σε λειτουργία, δοκιμές και παράδοση με οδηγίες χρήσης.');
    return works;
  }
  function boilerTypeFrom(name){
    var t=String(name||'').replace(/boiler/ig,'').replace(/μπ[όο][ιϊ]λερ/ig,'').replace(/\d+\s*(?:[-–]\s*\d+)?\s*lit\w*/ig,'').replace(/ΑΘ/g,'').replace(/\s+/g,' ').trim();
    return t||null;
  }

  // ---------- ZIP: ανάγνωση / γράψιμο ----------
  function rd16(u,o){return u[o]|u[o+1]<<8;}
  function rd32(u,o){return (u[o]|u[o+1]<<8|u[o+2]<<16|u[o+3]<<24)>>>0;}
  function parseZip(u8){
    var eocd=-1;
    for(var i=u8.length-22;i>=0;i--){if(rd32(u8,i)===0x06054b50){eocd=i;break;}}
    if(eocd<0)throw new Error('zip: EOCD not found');
    var count=rd16(u8,eocd+10), cdOff=rd32(u8,eocd+16);
    var entries=[], off=cdOff;
    var dec=new TextDecoder();
    for(var n=0;n<count;n++){
      if(rd32(u8,off)!==0x02014b50)throw new Error('zip: bad CD record');
      var nlen=rd16(u8,off+28), elen=rd16(u8,off+30), clen=rd16(u8,off+32);
      var e={
        cdStart:off, cdEnd:off+46+nlen+elen+clen,
        method:rd16(u8,off+10), csize:rd32(u8,off+20), usize:rd32(u8,off+24),
        lho:rd32(u8,off+42),
        name:dec.decode(u8.subarray(off+46,off+46+nlen))
      };
      var lnlen=rd16(u8,e.lho+26), lelen=rd16(u8,e.lho+28);
      e.dataStart=e.lho+30+lnlen+lelen;
      e.localEnd=e.dataStart+e.csize;
      entries.push(e);
      off=e.cdEnd;
    }
    return {entries:entries,eocd:eocd};
  }
  async function unzipEntry(u8,e){
    var comp=u8.subarray(e.dataStart,e.dataStart+e.csize);
    if(e.method===0)return new TextDecoder().decode(comp);
    if(e.method!==8)throw new Error('zip: unsupported method '+e.method);
    var ds=new DecompressionStream('deflate-raw');
    var ab=await new Response(new Blob([comp]).stream().pipeThrough(ds)).arrayBuffer();
    return new TextDecoder().decode(ab);
  }
  var CRC_T=(function(){var t=new Uint32Array(256);for(var n=0;n<256;n++){var c=n;for(var k=0;k<8;k++)c=(c&1)?(0xEDB88320^(c>>>1)):(c>>>1);t[n]=c>>>0;}return t;})();
  function crc32(u8){var c=0xFFFFFFFF;for(var i=0;i<u8.length;i++)c=CRC_T[(c^u8[i])&0xFF]^(c>>>8);return (c^0xFFFFFFFF)>>>0;}
  function wr16(u,o,v){u[o]=v&255;u[o+1]=(v>>>8)&255;}
  function wr32(u,o,v){u[o]=v&255;u[o+1]=(v>>>8)&255;u[o+2]=(v>>>16)&255;u[o+3]=(v>>>24)&255;}
  function rebuildZip(tpl,zinfo,newDocXml){
    var enc=new TextEncoder();
    var docBytes=enc.encode(newDocXml);
    var crc=crc32(docBytes);
    var parts=[], off=0, newOffsets={};
    function push(u){parts.push(u);off+=u.length;}
    zinfo.entries.forEach(function(e){
      newOffsets[e.name]=off;
      if(e.name==='word/document.xml'){
        var nameB=enc.encode(e.name);
        var lh=new Uint8Array(30+nameB.length);
        wr32(lh,0,0x04034b50);
        wr16(lh,4,20);            // version needed
        wr16(lh,6,0);             // flags
        wr16(lh,8,0);             // method: stored
        lh[10]=tpl[e.cdStart+12];lh[11]=tpl[e.cdStart+13]; // time
        lh[12]=tpl[e.cdStart+14];lh[13]=tpl[e.cdStart+15]; // date
        wr32(lh,14,crc);
        wr32(lh,18,docBytes.length);
        wr32(lh,22,docBytes.length);
        wr16(lh,26,nameB.length);
        wr16(lh,28,0);
        lh.set(nameB,30);
        push(lh);push(docBytes);
      }else{
        push(tpl.subarray(e.lho,e.localEnd));
      }
    });
    var cdStart=off;
    zinfo.entries.forEach(function(e){
      var rec=tpl.slice(e.cdStart,e.cdEnd);
      if(e.name==='word/document.xml'){
        wr16(rec,8,0);   // flags
        wr16(rec,10,0);  // method stored
        wr32(rec,16,crc);
        wr32(rec,20,docBytes.length);
        wr32(rec,24,docBytes.length);
      }
      wr32(rec,42,newOffsets[e.name]);
      push(rec);
    });
    var cdSize=off-cdStart;
    var eocd=new Uint8Array(22);
    wr32(eocd,0,0x06054b50);
    wr16(eocd,8,zinfo.entries.length);
    wr16(eocd,10,zinfo.entries.length);
    wr32(eocd,12,cdSize);
    wr32(eocd,16,cdStart);
    push(eocd);
    var total=new Uint8Array(off), p=0;
    parts.forEach(function(u){total.set(u,p);p+=u.length;});
    return total;
  }

  // ---------- Γέμισμα καλουπιού ----------
  function removeParaContaining(xml,needle){
    var i=xml.indexOf(needle);
    if(i<0)return xml;
    var a=Math.max(xml.lastIndexOf('<w:p ',i),xml.lastIndexOf('<w:p>',i));
    var b=xml.indexOf('</w:p>',i)+6;
    return xml.substring(0,a)+xml.substring(b);
  }
  function expandListMarker(xml,marker,lines){
    var i=xml.indexOf(marker);
    if(i<0)throw new Error('marker missing: '+marker);
    var a=Math.max(xml.lastIndexOf('<w:p ',i),xml.lastIndexOf('<w:p>',i));
    var b=xml.indexOf('</w:p>',i)+6;
    var proto=xml.substring(a,b);
    var out=lines.map(function(l){return proto.split(marker).join(escXml(l));}).join('');
    return xml.substring(0,a)+out+xml.substring(b);
  }
  function expandRowMarker(xml,rows){
    var i=xml.indexOf('@@ROWL@@');
    if(i<0)throw new Error('row marker missing');
    var a=xml.lastIndexOf('<w:tr ',i);
    var b=xml.indexOf('</w:tr>',i)+7;
    var proto=xml.substring(a,b);
    var out=rows.map(function(r){return proto.split('@@ROWL@@').join(escXml(r[0])).split('@@ROWV@@').join(escXml(r[1]));}).join('');
    return xml.substring(0,a)+out+xml.substring(b);
  }

  function buildingValues(ctx){
    var hl=ctx.hl||{};
    var v={};
    v.OWNER=ctx.custName||'—';
    v.ADDRESS=ctx.custAddress||'—';
    v.ERGO=[ctx.propName,ctx.propHeating].filter(Boolean).join(' — ')||'—';
    v.AREA=(hl.area!=null&&hl.area!=='')?String(hl.area):'—';
    v.EXTTEMP=ZONE_TEMP[hl.zone]||'—';
    v.WALL=hl.ins?((INS_LABEL[hl.ins]||hl.ins)+(hl.upWall?' — έχει γίνει θερμοπρόσοψη':'')):'—';
    v.WIN=hl.ins?(hl.upWin?'Διπλοί υαλοπίνακες — αναβαθμισμένα κουφώματα':((hl.ins==='kenak'||hl.ins==='nzeb')?'Σύγχρονα κουφώματα διπλών υαλοπινάκων':'Κουφώματα περιόδου κατασκευής')):'—';
    v.FLOORS=hl.floorType?((FLOOR_LABEL[hl.floorType]||hl.floorType)+(hl.upFloor?' — με μόνωση πυλωτής':'')):'—';
    v.CEIL=hl.ceilType?((CEIL_LABEL[hl.ceilType]||hl.ceilType)+(hl.upCeil?' — με μόνωση οροφής':'')):'—';
    return v;
  }

  async function buildDoc(ctx,model,opts){
    if(typeof DecompressionStream==='undefined'){alert('Ο browser δεν υποστηρίζει τη δημιουργία εγγράφου (χρειάζεται νεότερη έκδοση Chrome/Edge).');return;}
    var tpl=b64u8(TPL_B64);
    var zinfo=parseZip(tpl);
    var docEntry=zinfo.entries.filter(function(e){return e.name==='word/document.xml';})[0];
    if(!docEntry)throw new Error('template: document.xml missing');
    var xml=await unzipEntry(tpl,docEntry);

    // Φωτογραφία περιγραφής ανά οικογένεια: 'new' (monobloc-style) -> rId150 (image27.jpeg). Default rId25 = αρχική φωτο.
    if(model.photoNew&&model.photoNew(ctx.pumpName)){
      xml=xml.split('r:embed="rId25"').join('r:embed="rId150"');
    }

    var pumpSec=null,bufSec=null,boilSec=null;
    ctx.secs.forEach(function(s){
      if(s.id==='pump')pumpSec=s;
      else if(s.id==='buffer')bufSec=s;
      else if(s.id==='boiler')boilSec=s;
    });

    // 1) Αφαίρεση ενοτήτων που δεν υπάρχουν στην προσφορά
    if(!bufSec){
      xml=removeParaContaining(xml,'<w:t>Δοχείο αδρανείας – Υδραυλικός διαχωριστής</w:t>');
      xml=removeParaContaining(xml,'@@BUFLIT@@');
    }
    if(!boilSec){
      xml=removeParaContaining(xml,'<w:t>Ζεστό νερό χρήσης</w:t>');
      xml=removeParaContaining(xml,'@@BOILTYPE@@');
    }

    // 2) Λίστες υλικών / εργασιών
    xml=expandListMarker(xml,'@@MATS@@',materialsList(pumpSec,bufSec,boilSec,opts));
    xml=expandListMarker(xml,'@@WORKS@@',worksList(pumpSec,bufSec,boilSec,opts));

    // 3) Γραμμές πίνακα αξιών
    var rows=[['Προμήθεια αντλίας θερμότητας Atlantic '+ctx.pumpName+(ctx.pumpKw?' ('+ctx.pumpKw+')':''),fmtE(ctx.pumpRetail)]];
    ctx.secs.forEach(function(s){
      if(!s.retail||s.retail<=0)return;
      rows.push([s.label+' — υλικά & εργασία',fmtE(s.retail)]);
    });
    xml=expandRowMarker(xml,rows);

    // 4) Τιμές δοχείου / μπόιλερ
    if(bufSec){
      var tank=null;
      bufSec.items.forEach(function(i){if(!tank&&i.id!=='ci1'&&/δοχε[ίι]ο|lit/i.test(i.name))tank=i;});
      var bl=tank?litersFrom(tank.name):null;
      xml=xml.split('@@BUFLIT@@').join(escXml(bl||'—'));
    }
    if(boilSec){
      var bo=null;
      boilSec.items.forEach(function(i){if(!bo&&/boiler|μπ[όο][ιϊ]λερ/i.test(i.name))bo=i;});
      xml=xml.split('@@BOILTYPE@@').join(escXml((bo?boilerTypeFrom(bo.name):null)||'—'));
      xml=xml.split('@@BOILLIT@@').join(escXml((bo?litersFrom(bo.name):null)||'—'));
    }

    // 5) Απλές τιμές
    var bv=buildingValues(ctx);
    var map={
      DATE:ctx.todayStr,
      CUSTNAME:(ctx.custName?'κ. '+ctx.custName:'________________'),
      OWNER:bv.OWNER,ADDRESS:bv.ADDRESS,ERGO:bv.ERGO,AREA:bv.AREA,EXTTEMP:bv.EXTTEMP,
      WALL:bv.WALL,WIN:bv.WIN,FLOORS:bv.FLOORS,CEIL:bv.CEIL,
      TITLE:model.title(ctx),
      TECHA:model.techA(ctx),
      TECHB:model.techB(ctx),
      CAPTION:model.caption(ctx),
      ADV1:model.adv1(ctx),
      TOTAL:fmtE(ctx.totalNet),
      VAT:fmtE(ctx.vat),
      TOTALVAT:fmtE(ctx.totalWithVat)
    };
    Object.keys(map).forEach(function(k){
      xml=xml.split('@@'+k+'@@').join(escXml(map[k]));
    });
    if(xml.indexOf('@@')>=0){
      var at=xml.indexOf('@@');
      throw new Error('Έμεινε ασυμπλήρωτη σημαδούρα: '+xml.substring(at,at+30));
    }

    // 6) Ξαναπακετάρισμα και λήψη
    var out=rebuildZip(tpl,zinfo,xml);
    var blob=new Blob([out],{type:'application/vnd.openxmlformats-officedocument.wordprocessingml.document'});
    var url=URL.createObjectURL(blob);
    var a=document.createElement('a');
    a.href=url;
    a.download='Prosfora_'+(ctx.custName?ctx.custName.replace(/\s+/g,'_'):'Pelatis')+'_'+String(ctx.pumpName).replace(/\s+/g,'_')+'.docx';
    document.body.appendChild(a);a.click();document.body.removeChild(a);
    setTimeout(function(){URL.revokeObjectURL(url);},2000);
  }

  // ---------- Παράθυρο επιλογών ----------
  function showDialog(ctx,model){
    var old=document.getElementById('pg-ovl');if(old)old.remove();
    var ovl=document.createElement('div');
    ovl.id='pg-ovl';
    ovl.style.cssText='position:fixed;inset:0;background:rgba(15,23,42,.45);z-index:9999;display:flex;align-items:center;justify-content:center';
    var selStyle='width:100%;margin:4px 0 13px;padding:8px;border:1.5px solid #d1d5db;border-radius:7px;font-size:13px;background:#fff';
    ovl.innerHTML=
      '<div style="background:#fff;border-radius:12px;padding:22px 26px;width:440px;max-width:92vw;box-shadow:0 10px 40px rgba(0,0,0,.25)">'
      +'<h3 style="margin:0 0 4px;font-size:17px">📝 Στοιχεία περιγραφής</h3>'
      +'<div style="font-size:12.5px;color:#6b7280;margin-bottom:14px">'+model.seriesLabel+(ctx.pumpKw?' • '+ctx.pumpKw:'')+' — ό,τι μείνει κενό απλώς δεν θα αναφερθεί στο έγγραφο.</div>'
      +'<label style="font-weight:700;font-size:13px">Θέση τοποθέτησης εξωτερικής μονάδας</label>'
      +'<select id="pg-place" style="'+selStyle+'">'
      +'<option value="">— χωρίς αναφορά —</option>'
      +'<option>στο μπαλκόνι της κατοικίας</option>'
      +'<option>στην ταράτσα της κατοικίας</option>'
      +'<option>στην αυλή της κατοικίας</option>'
      +'<option>στον ακάλυπτο χώρο της οικοδομής</option>'
      +'</select>'
      +'<label style="font-weight:700;font-size:13px">Σύστημα διανομής θέρμανσης</label>'
      +'<select id="pg-dist" style="'+selStyle+'">'
      +'<option value="">— χωρίς αναφορά —</option>'
      +'<option>ενδοδαπέδια θέρμανση</option>'
      +'<option>θερμαντικά σώματα (καλοριφέρ)</option>'
      +'<option>fan coils</option>'
      +'</select>'
      +'<label style="display:flex;gap:8px;align-items:center;font-size:13.5px;margin:2px 0"><input type="checkbox" id="pg-rmboiler"> Αποσύνδεση υφιστάμενου λέβητα</label>'
      +'<label style="display:flex;gap:8px;align-items:center;font-size:13.5px;margin:6px 0 18px"><input type="checkbox" id="pg-rmtank"> Αποσύνδεση δεξαμενής πετρελαίου</label>'
      +'<div style="display:flex;gap:10px;justify-content:flex-end">'
      +'<button id="pg-cancel" style="border-radius:7px;padding:8px 18px;font-size:13px;font-weight:600;cursor:pointer;border:1.5px solid #d1d5db;background:#fff;color:#374151">Άκυρο</button>'
      +'<button id="pg-go" style="border-radius:7px;padding:8px 18px;font-size:13px;font-weight:600;cursor:pointer;border:1.5px solid #7c3aed;background:#7c3aed;color:#fff">Δημιουργία Word</button>'
      +'</div></div>';
    document.body.appendChild(ovl);
    document.getElementById('pg-cancel').onclick=function(){ovl.remove();};
    document.getElementById('pg-go').onclick=function(){
      var opts={
        place:document.getElementById('pg-place').value,
        dist:document.getElementById('pg-dist').value,
        rmBoiler:document.getElementById('pg-rmboiler').checked,
        rmTank:document.getElementById('pg-rmtank').checked
      };
      ovl.remove();
      buildDoc(ctx,model,opts).catch(function(e){alert('Σφάλμα δημιουργίας εγγράφου: '+(e&&e.message?e.message:e));});
    };
  }

  // ---------- Δημόσιο interface ----------
  return {
    version:3,
    start:function(ctx){
      var model=null;
      for(var i=0;i<MODELS.length;i++){if(MODELS[i].match(ctx)){model=MODELS[i];break;}}
      if(!model){
        alert('Δεν υπάρχουν ακόμη κείμενα περιγραφής για αυτό το μοντέλο.\nΔιαθέσιμες σειρές: '+MODELS.map(function(m){return m.seriesLabel;}).join(', ')+'.');
        return;
      }
      showDialog(ctx,model);
    }
  };
})();